Material.Shader:


varying vec3 normal,lightVec,viewVec, posi;


void main()
{
normal=gl_NormalMatrix*gl_Normal;
posi.xyz = gl_Vertex.xyz;
viewVec=-(gl_ModelViewMatrix*gl_Vertex).xyz;
lightVec=(gl_LightSource[0].position).xyz+viewVec;
gl_Position=ftransform();
gl_FrontColor = gl_Color;
gl_TexCoord[0]= gl_MultiTexCoord0;
gl_TexCoord[1]= gl_MultiTexCoord1;
}

float rand(vec2 n)
{
  return 0.5 + 0.5 *     fract(sin(dot(n.xy, vec2(12.9898, 78.233)))* 43758.5453);
}

varying vec3 normal,lightVec,viewVec, posi;
void main()
{
vec4 color=gl_Color;
float r = rand(posi.xy);
vec3 N=vec3(r,r,r);
N.x=N.x-0.5;
N.y=N.y-0.5;
N.z=N.z-0.5;
N=normalize(N);
vec3 L=normalize(lightVec);
vec3 V=normalize(viewVec);
vec3 R=normalize(2.0*dot(N,V)*N-V);
float LdotN=dot(L,N);
float LdotR=dot(L,R);
// diffuse

if(0.5 > LdotN)
 color=gl_Color*LdotN*2.0;
// speculaire
else if(LdotR > 0.7)
 color=gl_Color*LdotR*1.5-0.05;
vec4 temp = normalize(color) * vec4(N, 1.0);
gl_FragColor=vec4(temp.xyz, 1.0);
}
